#include <bits/stdc++.h>
using namespace std;
int main(){
    string a;
    int t=1,p;
    cin>>a;
    for(int i=0;i<a.size();i++){
        if(a[i]=='.'){
            t=2,p=i;
            break;
        }
        if(a[i]=='/'){
            t=3,p=i;
            break;
        }
        if(a[i]=='%'){
            t=4,p=i;
            break;
        }
    }
    if(t==1){
        for(int i=0,j=a.size()-1;i<j;i++,j--)swap(a[i],a[j]);
        int str=0;
        while(str<a.size()-1 && a[str]=='0')str++;
        for(;str<a.size();str++)cout<<a[str];
    }else if(t==2){
    	for(int i=0,j=p-1;i<j;i++,j--)swap(a[i],a[j]);
    	for(int i=p+1,j=a.size()-1;i<j;i++,j--)swap(a[i],a[j]);
    	int str=0,end=a.size()-1;
    	while(a[str]=='0' && str<p-1)str++;
    	while(a[end]=='0' && end>p+1)end--;
    	for(;str<=end;str++)cout<<a[str];
	}else if(t==3){
		int strf=0,strm=p+1;
		for(int i=0,j=p-1;i<j;i++,j--)swap(a[i],a[j]);
		for(int i=p+1,j=a.size()-1;i<j;i++,j--)swap(a[i],a[j]);
		int tmp=a.size()-1;
		while(a[strf]=='0' && strf<p-1)strf++;
    	while(a[strm]=='0' && strm<tmp)strm++;
    	for(int i=strf;i<p;i++)cout<<a[i];
    	cout<<"/";
    	for(int i=strm;i<a.size();i++)cout<<a[i];
	}else if(t==4){
		for(int i=0,j=a.size()-2;i<j;i++,j--)swap(a[i],a[j]);
		//cout<<a<<endl;
		int str=0;
		while(a[str]=='0' && str<a.size()-2)str++;
		//cout<<str<<endl;
		for(;str<a.size();str++)cout<<a[str];
	}
    return 0;
}
